def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        total_penalty = 0
        total_bonus = 0
        if ratio > 2:
            for p in range(1, 5):
                exp = 2 ** p
                total_penalty += (ratio ** exp) / (p * 3)
            priorities[i] = ratio ** 4 + total_penalty
        elif 1 < ratio <= 2:
            for x in range(1, 7):
                total_penalty += ((-1) ** x) * (ratio ** x) / (x + 1)
            priorities[i] = abs(total_penalty) * 8
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1 if j % 2 == 0 else 1
                score += sign * (ratio ** j) / (j ** 1.5)
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 7
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                for m in range(1, 5):
                    total_bonus += (ratio ** m) / (m * 2)
                priorities[i] += total_bonus
            if ratio < 0.1:
                priorities[i] *= 0.5
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
            continue
        if ratio >= 0.5 and ratio < 1.5 and capacity > item * 0.75:
            adjustment = 0
            for r in range(1, 4):
                adjustment += ((-1) ** (r+1)) * (ratio ** (2*r)) / (r + 2)
            priorities[i] *= (1 + 0.1 * adjustment)
        if capacities_are_prime(int(capacity)):
            priorities[i] *= 0.9
    return priorities
